// ── AutoFlow v3 · Procesar y calcular presupuesto ──
const raw = typeof $input.first().json.body === 'string'
  ? JSON.parse($input.first().json.body)
  : ($input.first().json.body || $input.first().json);

const now = new Date();
const fecha = now.toLocaleDateString('es-ES', {
  day: '2-digit', month: 'long', year: 'numeric'
});

// ── Campos del formulario ──
const servicios    = raw.servicios_seleccionados || raw.servicios || '';
const dolor        = raw.dolor_principal || raw.descripcion || '';
const horasPerdidas= raw.horas_perdidas || '5-15';
const personasManuales = raw.personas_manuales || '1';
const facturacion  = raw.facturacion || '';
const sedes        = parseInt(raw.sedes) || 1;
const madurez      = raw.madurez_digital || '';
const prioridad    = raw.prioridad || '';
const consecuencias= raw.consecuencias || '';
const intentoPrevio= raw.intento_previo || '';
const notasExtra   = raw.notas_extra || '';
const sectorLabel  = raw.sector_label || raw.sector || '';
const vol          = parseInt(raw.volumen_mensual) || 100;

// ── Complejidad ──
const sel = servicios.split('|').map(s => s.trim()).filter(Boolean);
let cx = 'Básica';
if (sel.length > 2 || vol > 150) cx = 'Media';
if (sel.length > 4 || vol > 300) cx = 'Avanzada';
if (sel.length > 6) cx = 'Premium';

// ── Precios base por automatización ──
const priceMap = {
  'Gestión de citas y agendas': 1800,
  'Chatbot de atención al cliente': 2200,
  'Recordatorios automáticos': 900,
  'Integración CRM y bases de datos': 1400,
  'Generación de documentos y PDFs con IA': 1200,
  'Email y WhatsApp marketing': 900,
  'Facturación y presupuestos automáticos': 1100,
  'Reportes y dashboards automáticos': 800,
  'E-commerce y gestión de pedidos': 1600,
  'Procesos internos de RRHH y onboarding': 1000,
  'Seguimiento y nurturing de leads': 1100,
  'Notificaciones y alertas internas': 700
};

let base = 1500;
sel.forEach(s => { base += (priceMap[s] || 700); });

// Multiplicadores
const volMult  = vol > 400 ? 1.3 : vol > 250 ? 1.18 : vol > 150 ? 1.1 : 1;
const eqMap    = { '1-3': 0.9, '4-10': 1, '11-30': 1.12, '31-100': 1.22, '100+': 1.35 };
const sedesMul = sedes >= 15 ? 1.35 : sedes >= 6 ? 1.2 : sedes >= 2 ? 1.1 : 1;
base = Math.round(base * volMult);
base = Math.round(base * (eqMap[raw.equipo] || 1));
base = Math.round(base * sedesMul);
const total = Math.round(base / 250) * 250;

// Desglose interno
const dev           = Math.round(total * 0.55 / 100) * 100;
const integraciones = Math.round(total * 0.25 / 100) * 100;
const testing       = total - dev - integraciones;

// Opciones de pago
const p2ini = Math.round(total * 0.45 / 250) * 250;
const p2mes = Math.round((total * 0.65 / 18) / 50) * 50;
const p3    = Math.round((total * 1.1 / 12) / 50) * 50;

// ROI
const horasMap    = { '1-5': 3, '5-15': 10, '15-30': 22, '30+': 40 };
const personasMap = { '1': 1, '2-3': 2.5, '4-6': 5, '7+': 8 };
const hrsSemanales= horasMap[horasPerdidas] || 10;
const numPersonas = personasMap[personasManuales] || 2;
const hrsMes      = Math.round(hrsSemanales * 4 * numPersonas * 0.75 / 5) * 5;
const ahorro      = Math.round(hrsMes * 18 * 12 / 500) * 500;
const roiMeses    = Math.round((total / (ahorro / 12)) * 10) / 10;

// Número de propuesta (timestamp corto)
const numProp = 'AF-' + now.getFullYear() + String(now.getMonth()+1).padStart(2,'0') + String(now.getDate()).padStart(2,'0') + '-' + String(now.getHours()).padStart(2,'0') + String(now.getMinutes()).padStart(2,'0');

return [{
  json: {
    FECHA_SOLICITUD:      fecha,
    NUM_PROPUESTA:        numProp,
    NOMBRE:               (raw.nombre || '').trim(),
    EMPRESA:              raw.empresa || '',
    SECTOR:               sectorLabel,
    EQUIPO:               raw.equipo || '',
    EMAIL:                raw.email || '',
    TELEFONO:             raw.telefono || '',
    VOLUMEN_MENSUAL:      vol,
    SERVICIOS:            sel.join(', ') || 'No especificados',
    HERRAMIENTAS:         raw.herramientas || '',
    DESCRIPCION:          dolor,
    HORAS_PERDIDAS:       horasPerdidas,
    PERSONAS_MANUALES:    personasManuales,
    FACTURACION:          facturacion,
    SEDES:                sedes,
    MADUREZ_DIGITAL:      madurez,
    PRIORIDAD:            prioridad,
    CONSECUENCIAS:        consecuencias,
    INTENTO_PREVIO:       intentoPrevio,
    NOTAS_EXTRA:          notasExtra,
    MODELO_PAGO:          raw.modelo_pago || 'indiferente',
    DISPONIBILIDAD:       raw.disponibilidad || '',
    URGENCIA:             raw.urgencia || '',
    COMPLEJIDAD:          cx,
    PRECIO_UNICO:         total.toLocaleString('es-ES') + ' EUR',
    PRECIO_UNICO_NUM:     total,
    PRECIO_INICIAL:       p2ini.toLocaleString('es-ES') + ' EUR',
    PRECIO_MENSUAL_MIXTO: p2mes + ' EUR/mes',
    PRECIO_SOLO_MENSUAL:  p3 + ' EUR/mes',
    PRECIO_DEV:           dev.toLocaleString('es-ES') + ' EUR',
    PRECIO_INTEGRACIONES: integraciones.toLocaleString('es-ES') + ' EUR',
    PRECIO_TESTING:       testing.toLocaleString('es-ES') + ' EUR',
    HORAS_LIBERADAS_MES:  hrsMes + 'h',
    AHORRO_ESTIMADO:      ahorro.toLocaleString('es-ES') + ' EUR/año',
    ROI_MESES:            roiMeses + ' meses',
    ESTADO:               'Nuevo',
    PDF_ENVIADO:          'NO',
    NOTAS:                ''
  }
}];

// ── AutoFlow v3 · Preparar datos para PDF ──
const datos = $('Procesar y calcular presupuesto').first().json;

// Extraer el texto generado por GPT-4.1
const iaRaw = $input.first().json;
const analisis = iaRaw?.output?.[0]?.content?.[0]?.text
  || iaRaw?.text
  || iaRaw?.content
  || iaRaw?.message?.content
  || '';

if (!analisis) {
  throw new Error('GPT no devolvió contenido. Revisar configuración del nodo OpenAI.');
}

const payload = {
  // Identificación
  num_propuesta:        datos.NUM_PROPUESTA,
  nombre:               datos.NOMBRE,
  empresa:              datos.EMPRESA,
  sector:               datos.SECTOR,
  equipo:               datos.EQUIPO,
  email:                datos.EMAIL,
  telefono:             datos.TELEFONO,
  fecha:                datos.FECHA_SOLICITUD,
  // Proyecto
  volumen_mensual:      String(datos.VOLUMEN_MENSUAL),
  servicios:            datos.SERVICIOS,
  herramientas:         datos.HERRAMIENTAS,
  descripcion:          datos.DESCRIPCION,
  complejidad:          datos.COMPLEJIDAD,
  // Precios
  modelo_pago:          datos.MODELO_PAGO,
  precio_unico:         datos.PRECIO_UNICO,
  precio_inicial:       datos.PRECIO_INICIAL,
  precio_mensual_mixto: datos.PRECIO_MENSUAL_MIXTO,
  precio_solo_mensual:  datos.PRECIO_SOLO_MENSUAL,
  precio_dev:           datos.PRECIO_DEV,
  precio_integraciones: datos.PRECIO_INTEGRACIONES,
  precio_testing:       datos.PRECIO_TESTING,
  // ROI
  horas_liberadas_mes:  datos.HORAS_LIBERADAS_MES,
  ahorro_estimado:      datos.AHORRO_ESTIMADO,
  roi_meses:            datos.ROI_MESES,
  // Contexto
  horas_perdidas:       datos.HORAS_PERDIDAS,
  personas_manuales:    datos.PERSONAS_MANUALES,
  intento_previo:       datos.INTENTO_PREVIO,
  consecuencias:        datos.CONSECUENCIAS,
  prioridad:            datos.PRIORIDAD,
  disponibilidad:       datos.DISPONIBILIDAD,
  // IA
  analisis_ia:          analisis
};

return [{ json: { payload } }];

// ── AutoFlow v3 · Generar HTML del PDF ──
const p = $input.first().json.payload;

// ── Parser de secciones IA ──────────────────────────
function parseSecciones(texto) {
  if (!texto) return '<p style="color:red">Error: no se recibió análisis de IA.</p>';

  const partes = texto.split(/===([^=]+)===/g);
  let html = '';

  for (let i = 1; i < partes.length; i += 2) {
    const titulo  = partes[i].trim();
    const cuerpo  = (partes[i + 1] || '').trim();

    const parrafos = cuerpo.split(/\n\n+/).map(bloque => {
      bloque = bloque.trim();
      if (!bloque) return '';

      // Bloque de automatización
      if (/^AUTOMATIZACIÓN\s*\d+[:.]/.test(bloque)) {
        const lineas = bloque.split('\n');
        const tituloAuto = lineas[0];
        const resto = lineas.slice(1).map(linea => {
          const m = linea.match(/^([^:]+):\s*(.+)/);
          if (!m) return `<p class="auto-p">${linea}</p>`;
          const label   = m[1].trim();
          const content = m[2].trim();
          if (label === 'Inversión') {
            return `<div class="auto-field"><span class="auto-label">${label}</span><span class="auto-precio">${content}</span></div>`;
          }
          return `<div class="auto-field"><span class="auto-label">${label}</span><span class="auto-content">${content}</span></div>`;
        }).join('');
        return `<div class="auto-bloque"><div class="auto-titulo">${tituloAuto}</div>${resto}</div>`;
      }

      // Paso de implementación
      if (/^Paso \d+/.test(bloque)) {
        return `<div class="paso-bloque">${bloque.replace(/\n/g, '<br>')}</div>`;
      }

      // Párrafo normal
      return `<p>${bloque.replace(/\n/g, ' ')}</p>`;
    }).join('');

    html += `
      <div class="seccion page-safe">
        <h2>${titulo}</h2>
        <div class="seccion-body">${parrafos}</div>
      </div>`;
  }

  return html || '<p>No se encontraron secciones en el análisis.</p>';
}

// ── Bloque de precio según modelo ───────────────────
function getPrecioHTML() {
  const m = p.modelo_pago;
  if (m === 'unico') return `
    <div class="precio-destacado">
      <div class="precio-tipo">Inversión — Pago único</div>
      <div class="precio-val">${p.precio_unico}</div>
      <div class="precio-desc">Sistema en propiedad permanente. Sin cuotas ni dependencias futuras.</div>
    </div>`;
  if (m === 'mixto') return `
    <div class="precio-destacado">
      <div class="precio-tipo">Inversión — Pago mixto</div>
      <div class="precio-val">${p.precio_inicial} <span style="font-size:18px">+</span> ${p.precio_mensual_mixto}</div>
      <div class="precio-desc">Entrada inicial y el resto en 18 cuotas cómodas. El sistema queda en propiedad al finalizar.</div>
    </div>`;
  if (m === 'mensual') return `
    <div class="precio-destacado">
      <div class="precio-tipo">Inversión — Cuota mensual</div>
      <div class="precio-val">${p.precio_solo_mensual}</div>
      <div class="precio-desc">Sin inversión inicial. Mantenimiento y soporte incluidos cada mes.</div>
    </div>`;
  // indiferente → tres opciones
  return `
    <div class="precios-tres">
      <div class="precio-card">
        <div class="precio-tipo">Pago único</div>
        <div class="precio-val-sm">${p.precio_unico}</div>
        <div class="precio-desc-sm">Propiedad total. Sin cuotas.</div>
      </div>
      <div class="precio-card best">
        <div class="precio-tipo">⭐ Mixto (recomendado)</div>
        <div class="precio-val-sm">${p.precio_inicial} + ${p.precio_mensual_mixto}</div>
        <div class="precio-desc-sm">Entrada + 18 cuotas. Propiedad al finalizar.</div>
      </div>
      <div class="precio-card">
        <div class="precio-tipo">Cuota mensual</div>
        <div class="precio-val-sm">${p.precio_solo_mensual}</div>
        <div class="precio-desc-sm">Sin inversión inicial. Soporte incluido.</div>
      </div>
    </div>`;
}

// ── Métricas ROI ─────────────────────────────────────
const metricasROI = `
  <div class="metricas-roi">
    <div class="metrica">
      <div class="metrica-val">${p.horas_liberadas_mes}</div>
      <div class="metrica-lbl">Horas liberadas / mes</div>
    </div>
    <div class="metrica">
      <div class="metrica-val">${p.ahorro_estimado}</div>
      <div class="metrica-lbl">Ahorro anual estimado</div>
    </div>
    <div class="metrica">
      <div class="metrica-val">${p.roi_meses}</div>
      <div class="metrica-lbl">Retorno de inversión</div>
    </div>
  </div>`;

// ── Desglose de precio ───────────────────────────────
const desgloseHTML = `
  <div class="desglose">
    <div class="desglose-titulo">Desglose de la inversión</div>
    <div class="desglose-fila"><span>Desarrollo e implementación</span><span>${p.precio_dev}</span></div>
    <div class="desglose-fila"><span>Integraciones y configuración</span><span>${p.precio_integraciones}</span></div>
    <div class="desglose-fila"><span>Testing y puesta en marcha</span><span>${p.precio_testing}</span></div>
    <div class="desglose-fila incluido"><span>Soporte primer mes</span><span>Incluido</span></div>
  </div>`;

// ── HTML del análisis IA ─────────────────────────────
const seccionesHTML = parseSecciones(p.analisis_ia);

